def retrieve_context(query):
    results = finder.get_nearest_neighbors_by_vector(query, k=10)  # Get top-k most similar sentences
    context = ""
    for result in results:
        paragraphs = result['text'].split('. ')  # Assume each document consists of one long text and split into paragraphs based on '.'
        for paragraph in paragraphs:
            if query.lower() in paragraph.lower():  # Check if the query is within this paragraph
                context += paragraph + ". "  # If yes, add it to our result context
